-- Latvia – Student Residence Permit (National D Visa) — 30 FAQs
UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee student visa approval?","a":"No. Embassy decides based on admission, funds, and credibility. Never promise approval."},{"q":"What is proof of funds for Latvia?","a":"Typically €620/month × 12 (verify PMLP amount) months (€7,440/year) living funds or equivalent. Verify current amount on www.pmlp.gov.lv before quoting."},{"q":"Proof of funds amount for 2026?","a":"Typically €620/month × 12 (verify PMLP amount) (€7,440/year). Verify current amount on www.pmlp.gov.lv before quoting."},{"q":"Can spouse accompany?","a":"Dependants may apply separately; prove additional funds and accommodation. Assess case-by-case."},{"q":"English-taught programs need Latvian?","a":"Depends on program—follow admission and embassy requirements."},{"q":"How long to convert to residence permit?","a":"Apply at Migration Department (www.pmlp.gov.lv) soon after arrival and university registration."},{"q":"Can I work on student visa?","a":"Limited working hours permitted—verify current rules for students in Latvia."},{"q":"What after graduation?","a":"Discuss Graduate job-search temporary residence permit (verify on www.pmlp.gov.lv) separately."},{"q":"What is Description for this service?","a":"National visa (Type D) for study at a recognised Latvian university. After entry, apply for temporary residence permit at Migration Department (www.pmlp.gov.lv)."},{"q":"What is Eligible applicants for this service?","a":"University admission letter · Proof of funds (€620/month × 12 (verify PMLP amount)) · Health insurance · Motivation letter · Valid passport · Language proficiency as required"},{"q":"What is Proof of funds for this service?","a":"€620/month × 12 (verify PMLP amount) months (€7,440/year) typically required unless scholarship or sponsor alternative applies."},{"q":"Important note on Proof of funds?","a":"€620/month × 12 (verify PMLP amount) months (€7,440/year) typically required unless scholarship or sponsor alternative applies."},{"q":"What is Key authority for this service?","a":"Latvian Embassy/Consulate in India · VFS Global Latvia · Migration Department (www.pmlp.gov.lv) after arrival"},{"q":"What is After approval for this service?","a":"Enter Latvia; register address; apply for temporary residence permit at Migration Department (www.pmlp.gov.lv) within visa validity."},{"q":"Is Admission from recognised Latvian institution required?","a":"Admission from recognised Latvian institution is typically required."},{"q":"Is Proof of funds (€620/month × 12 (verify PMLP amount)) required?","a":"Apply early—processing takes weeks"},{"q":"Is Proof of funds or financial proof required?","a":"€7,440/year or equivalent with 3–6 month bank history"},{"q":"Is Health insurance (travel + statutory) required?","a":"Assess whether Health insurance (travel + statutory) is satisfied for this case."},{"q":"Is Motivation letter and CV required?","a":"Motivation letter and CV is typically required."},{"q":"Is Language proficiency (as required) required?","a":"Latvian or English per program"},{"q":"Is Valid passport required?","a":"Valid passport is typically required."},{"q":"What is the Processing time?","a":"6–12w — After complete file complete"},{"q":"What is the Government fee?","a":"€75 — + proof of funds required living funds"},{"q":"What is the Our approval rate?","a":"88% — ~74% benchmark"},{"q":"What is the Required docs?","a":"15 — + proof of funds €7,440"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & third-party"},{"q":"What if the client has Proof of funds insufficient?","a":"Open blocked account or show €7,440 equivalent with 3–6 month bank history before embassy slot"},{"q":"Why is Proof of funds insufficient a problem?","a":"Proof of funds below €620/month × 12 (verify PMLP amount) or inconsistent bank history."},{"q":"What if the client has Insufficient proof of funds?","a":"Open proof of funds at approved bank for full required amount"},{"q":"Why is Insufficient proof of funds a problem?","a":"Amount below required monthly sum or not from recognised provider."}]'::jsonb
), updated_at = now()
